#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 dither = 0;
dz.x = 2*lum(texture(sampler_main,vUv+hor+dither).b - texture(sampler_main,vUv-hor+dither).b);
dz.y = 2*lum(texture(sampler_main,vUv+ver+dither).b - texture(sampler_main,vUv-ver+dither).b);

uv1 = vUvOriginal-vec2 (q3,0.4 + q4*0.4);
z = dist(uv1) -mix(GetPixel(vUvOriginal).r,GetBlur1(vUvOriginal).r,.5)*.03;
uv2 = vec2 (uv1.x*pow(z,1),z);
uv2 += vec2(0,-uTime*.014);

uv3 = uv2 +.07*noise4(uv2*1.5+vec2(0,uTime*.004));
cloud = 1-1.5*abs(texture(sampler_noise_hq,uv3/2)-.5);

float glow = texture(sampler_noise_hq,uv2*vec2(2,.5));
glow = clamp01(glow+.5 -3*abs(uv2.x));
cloud *= glow;

float k1 = 1.0/8.0*int(8*pow(cloud,4));
float noise = texture(sampler_noise_hq,18*(uv2+.05*cloud+vec2(0,-.01*uTime*k1)))-.75;
cloud *= 1+.2*noise*pow(cloud,2)  ;

float k5 = .7;
ret.r = (1-k5)*cloud + k5*GetPixel(vUvOriginal);

//in comp fast exakt kopieren !!!!!
uv1 = vUv- vec2 (0,.71);
smask =  10*uv1.y+GetBlur1(vUv).r/2-1;
mask2=  clamp01(smask);

//noise = 4*mask2*(1-mask2)*(texture(sampler_noise_hq,uv1*8+rand_frame).x-0.5);
mask =         clamp01(12*smask+noise);

uv1 = vUv-.7;
ret.b = 4*mask*(1-mask)* clamp01(GetPixel(vUvOriginal).r-0.2)
       + GetPixel(vUv+dz*.003).b -.03*length(dz) - pow(GetBlur1(vUv).b,8)*.2 - 0.01 ;

ret.g = GetPixel(mix(vUv,vUvOriginal,0.5)).g* (0.9 - 0.15*texture(sampler_noise_lq,vUv)) ;
ret.g = GetPixel(mix(vUv,vUvOriginal,0.5)).g* (0.85-0.2*GetBlur1(vUv).g) ;

ret.r += texture(sampler_noise_lq,2*uv2)*0.08 * clamp01(1-3*ret.r); //#


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv += uTexSize.zw/2;
uv1 = vUv- vec2 (0,.7);
smask =  10*uv1.y+GetBlur1(vUv).r/2-1;
mask2 =  clamp01(2*smask+0.3);

noise = 3*(1-mask2)*(texture(sampler_noise_lq,uv1*1.5+rand_frame*0.2).x);
mask =         clamp01(12*smask+noise/2);

z = .35/(uv1.y) + noise/2;

rs0.x = uv1.x * z; rs0.y = z ;
rs = vec2 (rs0.x+uTime/4, rs0.y+uTime*.21)*mask;
water = texture(sampler_noise_hq,rs) + texture(sampler_noise_hq,rs/4-uTime/8)-1;

//Lava

ret = lavcol ((GetPixel(vUv).r-dunk)*(1-mask*pow(vUv.y,4)));
ret += (1-GetPixel(vUv).r)*(1-mask)* abs(GetPixel(vUv-hor).r - GetPixel(vUv+hor).r) * lavcol(GetBlur2(vUv+0.03).r)*q9;
smoke = GetBlur1(vUv).b;

//Reflektion
vec2 uv3 = vec2(vUv.x,0.85-uv1.y+water*.2*q10);
ret += lavcol(GetPixel(uv3).r+GetPixel(uv3).g-dunk)*(mask)*0.85;

mask = clamp01(18*uv1.y-1.2*(1-GetBlur1(vUv).r));
float ufer = 3.6*mask2* (1-mask2);
ret *= clamp01(1-smoke*(1-ufer)) * clamp01(1-ufer * (rand_preset.x > 0.5));

//ret += smoke * vec3 (1,0.84,0.62)*0.8;
ret += smoke * lum(GetBlur3(vUv).rg*vec2(3,5))*vec3 (1,0.84,0.62);

//Partikel
ret += lavcol(sat(GetPixel(vUv).g));
ret = mix(sat(ret), lavcol(0.6), pow(1-vUv.y-(vUv.x-0.5)*(q3-0.5),4)*q1);


//ret = GetPixel(vUv).g;

  fragColor = ret;
}
